// // This module disables the ADC input when enabled
module adc_interface (
    input [23:0] data_in,
    input enable,
    output reg [23:0] data_out
);
    always @(*) begin
        if (enable) begin
            data_out = data_in;
        end else begin
            data_out = 24'b0;
        end
    end
endmodule
